<?php
namespace App\Models;
use Illuminate\Database\Eloquent\Model;
class Complaint extends Model { protected $fillable=['reference_no','title','description','category_id','complainant_type','complainant_name','complainant_email','complainant_phone','client_id','assignee_id','department_id','severity','status','source','received_date','acknowledged_date','target_resolution_date','actual_resolution_date','root_cause','resolution','customer_satisfaction','is_regulatory','escalation_level','escalated_to_id','capa_required','capa_id','attachments']; protected $casts=['attachments'=>'array','received_date'=>'datetime','acknowledged_date'=>'datetime','target_resolution_date'=>'datetime','actual_resolution_date'=>'datetime','is_regulatory'=>'boolean','capa_required'=>'boolean']; public function category(){ return $this->belongsTo(ComplaintCategory::class); } public function client(){ return $this->belongsTo(Client::class); } public function assignee(){ return $this->belongsTo(User::class,'assignee_id'); } public function department(){ return $this->belongsTo(Department::class); } public function escalatedTo(){ return $this->belongsTo(User::class,'escalated_to_id'); } public function capa(){ return $this->belongsTo(Capa::class); } public function updates(){ return $this->hasMany(ComplaintUpdate::class); } }
